import asyncio
from tenacity import retry, stop_after_attempt, wait_exponential

class LLMClient:
    def __init__(self, circuit_open_threshold=5, circuit_reset_seconds=60):
        self._failure_count = 0
        self._circuit_open = False
        self._threshold = circuit_open_threshold

    async def complete(self, prompt: str) -> str:
        if self._circuit_open:
            # Return cached fallback instead of propagating failure
            return self._fallback_response(prompt)

        try:
            result = await self._call_upstream(prompt)
            self._failure_count = 0
            return result
        except Exception as e:
            self._failure_count += 1
            if self._failure_count >= self._threshold:
                self._circuit_open = True
                asyncio.create_task(self._reset_after(self._reset_seconds))
            raise

